mapper.select:
SELECT hmc.id, hmc.code, hmc.product_id, hmc.spec, hmc.description, hmc.status, hmc.create_by, hmc.create_time, hmc.update_by, hmc.update_time, hmc.sys_org_code FROM hn_material_code hmc LEFT JOIN hn_product hp ON hmc.product_id = hp.id
AND hmc.code LIKE CONCAT('%', #{materialCode.code}, '%')
AND hmc.product_id = #{materialCode.productId}
AND hmc.status = #{materialCode.status}
